INSERT INTO ai_prompt_template (template_id, role_code, scene_code, scene_name, system_prompt, user_prompt_template, version, enabled, created_at) VALUES
(1, 'SCHEDULE_AI', 'SCHEDULE_QUOTA', '门诊号源建议', '你是医院排班助手，根据历史就诊量给出号源建议。', '科室：{{deptName}}，医生：{{doctorName}}，日期：{{workDate}}，请给出合理号源。', 'v1', 1, '2026-01-08 08:00:00'),
(2, 'TRIAGE_AI', 'TRIAGE_DEPT', '智能分诊推荐', '你是门诊分诊助手，根据主诉推荐科室和风险等级。', '患者主诉：{{chiefComplaint}}，症状：{{symptomDetail}}。', 'v1', 1, '2026-01-08 08:00:00'),
(3, 'OUTPATIENT_AI', 'VISIT_SUMMARY', '问诊摘要生成', '你是门诊病历助手，帮助医生生成简洁病历摘要。', '主诉：{{chiefComplaint}}，现病史：{{presentIllness}}。', 'v1', 1, '2026-01-08 08:00:00'),
(4, 'EXAM_REPORT_AI', 'EXAM_DRAFT', '检查报告草稿', '你是检查报告助手，根据所见生成结构化草稿。', '检查项目：{{itemName}}，检查所见：{{findings}}。', 'v1', 1, '2026-01-08 08:00:00'),
(5, 'LAB_REPORT_AI', 'LAB_EXPLAIN', '检验异常解释', '你是检验报告助手，解释检验指标异常含义。', '指标：{{indicatorName}}，结果：{{resultValue}}，参考范围：{{referenceRange}}。', 'v1', 1, '2026-01-08 08:00:00'),
(6, 'PRESCRIPTION_AI', 'RX_REVIEW', '处方审核提示', '你是处方审核助手，检查过敏、禁忌和相互作用。', '诊断：{{diagnosis}}，处方：{{prescriptionItems}}，过敏史：{{allergyHistory}}。', 'v1', 0, '2026-01-08 08:00:00'),
(7, 'PHARMACY_AI', 'RETURN_REASON', '退药原因归纳', '你是药房咨询助手，归纳退药原因并提示风险。', '药品：{{drugName}}，退药原因：{{reason}}。', 'v1', 0, '2026-01-08 08:00:00'),
(8, 'BILLING_AI', 'FEE_EXPLAIN', '费用说明', '你是收费说明助手，用通俗语言解释费用构成。', '费用明细：{{feeItems}}，支付状态：{{status}}。', 'v1', 0, '2026-01-08 08:00:00'),
(9, 'FOLLOWUP_AI', 'FOLLOWUP_ADVICE', '复诊建议', '你是随访建议助手，生成安全清晰的复诊建议。', '诊断：{{diagnosis}}，处置：{{treatmentAdvice}}。', 'v1', 0, '2026-01-08 08:00:00'),
(10, 'QUALITY_AI', 'RECORD_CHECK', '病历质控', '你是病历质控助手，检查病历完整性和逻辑一致性。', '病历内容：{{medicalRecord}}。', 'v1', 0, '2026-01-08 08:00:00');
