INSERT INTO ai_consultation (consultation_id, patient_id, chief_complaint, symptom_detail, ai_summary, recommended_dept_id, risk_level, ai_result, status, created_at) VALUES
(1, 1, '鼻塞流涕三天', '伴咽痛，无明显发热，青霉素过敏史。', '考虑上呼吸道感染或过敏性鼻炎急性发作。', 2, '普通', '建议呼吸科门诊，避免青霉素类用药。', '已生成', '2026-07-01 07:20:00'),
(2, 2, '血压波动一周', '最高160/96mmHg，偶有头胀，无胸痛。', '高血压控制不佳，需要心内科评估。', 1, '普通', '建议心血管内科就诊，完善心电图。', '已生成', '2026-07-01 07:22:00'),
(3, 3, '发热咳嗽两天', '体温最高38.5度，咳黄痰，头孢过敏。', '儿童急性呼吸道感染可能。', 5, '普通', '建议儿科门诊，关注体温和呼吸频率。', '已生成', '2026-07-01 07:24:00'),
(4, 4, '空腹血糖升高', '近期空腹血糖8.2mmol/L，口干多饮。', '2型糖尿病血糖控制欠佳。', 4, '普通', '建议内分泌科复诊，完善糖化血红蛋白。', '已生成', '2026-07-01 07:26:00'),
(5, 5, '反复胃痛一周', '餐后上腹痛明显，伴嗳气反酸。', '慢性胃炎或胃食管反流可能。', 3, '普通', '建议消化内科门诊，必要时胃镜评估。', '已生成', '2026-07-01 07:28:00'),
(6, 6, '夜间喘息加重', '既往哮喘，近两天夜间喘息，活动后气促。', '哮喘急性加重风险。', 2, '紧急', '建议优先呼吸科或急诊评估，监测血氧。', '已采纳', '2026-07-01 07:30:00'),
(7, 7, '胸闷胸痛半小时', '胸骨后压榨样痛，向左肩放射，冠心病史。', '急性冠脉综合征需排除。', 1, '紧急', '建议立即急诊绿色通道并完善心电图和肌钙蛋白。', '已采纳', '2026-07-01 07:32:00'),
(8, 8, '咳嗽咳痰十天', '慢阻肺史，黄痰增多，活动耐量下降。', '慢阻肺急性加重可能。', 2, '紧急', '建议呼吸科优先就诊，必要时胸部CT。', '已采纳', '2026-07-01 07:34:00'),
(9, 9, '剧烈头痛伴恶心', '偏头痛史，本次疼痛较以往明显。', '需排除继发性头痛。', 1, '紧急', '建议优先评估生命体征，必要时头颅CT。', '已采纳', '2026-07-01 07:36:00'),
(10, 10, '儿童皮疹伴喘息', '牛奶蛋白过敏史，进食后出现皮疹和轻度喘息。', '食物过敏反应，需警惕进展。', 5, '紧急', '建议儿科优先处理，观察呼吸道症状。', '已采纳', '2026-07-01 07:38:00'),
(11, 11, '甲状腺结节复查', '无吞咽困难，无声音嘶哑。', '甲状腺结节随访，可门诊完善超声。', 4, '普通', '建议内分泌科复诊并预约甲状腺彩超。', '已忽略', '2026-07-01 07:40:00'),
(12, 12, '咽部异物感', '晨起明显，伴轻微咳嗽。', '慢性咽炎或反流相关咽喉症状。', 2, '普通', '建议呼吸科或消化科评估。', '已忽略', '2026-07-01 07:42:00'),
(13, 13, '右上腹隐痛', '胆囊结石术后，近期油腻饮食后不适。', '消化系统功能异常可能。', 3, '普通', '建议消化内科门诊，完善肝胆胰脾超声。', '已忽略', '2026-07-01 07:44:00'),
(14, 14, '头晕伴血压升高', '血压150/92mmHg，未规律服药。', '高血压控制不佳。', 1, '普通', '建议心内科调整降压方案。', '已忽略', '2026-07-01 07:46:00'),
(15, 15, '皮肤瘙痒伴鼻塞', '芒果过敏史，近期接触花粉后加重。', '过敏性疾病可能。', 5, '普通', '建议儿科或过敏相关门诊评估。', '已忽略', '2026-07-01 07:48:00');
