(6, 6, 6, 21, 11, 'REP202607010006', '检查', '心影大小正常，双肺未见实变。', '胸片未见明显异常。', 'AI提示胸片基本正常。', '同意发布。', '已发布', '2026-07-01 10:25:00', '2026-07-01 10:05:00'),
(7, 7, 7, 22, 12, 'REP202607010007', '检查', '腹部脏器形态大小未见明显异常。', '腹部彩超未见明显异常。', 'AI提示腹部超声基本正常。', '同意发布。', '已发布', '2026-07-01 10:26:00', '2026-07-01 10:06:00'),
